      "notes": "Technical/Soft skills required by JD that are weak or missing in CV."
    },
    {
      "criteria": "Formatting & Structure",
      "score": 0-10,
      "grade": "Grade",
      "notes": "readability and professional layout assessment."
    }
  ],
  "overall_assessment": {
    "total_score": {
      "obtained": Number,
      "max": 50,
      "percent": Number
    },
    "classification": "Needs Improvement / Strong Candidate / Top Tier",
