// Loop over input items
return items.map(item => {
  const data = item.json.output;

  // التأكد من وجود البيانات
  if (!data) {
    return { json: { text: "⚠️ No report data found." } };
  }

  // 1. Header & Basic Info
  let text = `📄 *CV Analysis Report*\n`;
  text += `━━━━━━━━━━━━━━━━━━\n`;
  text += `👤 *Candidate:* ${data.basic_information.applicant_name}\n`;
  text += `🎯 *Role:* ${data.basic_information.position_applied}\n`;
  text += `📅 *Date:* ${data.analysis_date}\n\n`;

  // 2. Overall Score
  const score = data.overall_assessment;
  const scoreEmoji = score.total_score.percent >= 70 ? "🟢" : (score.total_score.percent >= 50 ? "🟡" : "🔴");

  text += `📊 *Overall Performance*\n`;
  text += `${scoreEmoji} **Score:** ${score.total_score.obtained}/${score.total_score.max} (${score.job_match})\n`;
  text += `🏷️ **Verdict:** ${score.classification}\n`;
  text += `━━━━━━━━━━━━━━━━━━\n\n`;

  // 3. Detailed Breakdown
  text += `📝 *Detailed Breakdown*\n`;
  if (data.analysis_results && Array.isArray(data.analysis_results)) {
    data.analysis_results.forEach(criterion => {
      // تحديد أيقونة بناءً على الدرجة
      const gradeIcon = criterion.score >= 4 ? "✅" : (criterion.score >= 3 ? "⚠️" : "❌");

      text += `${gradeIcon} *${criterion.criteria}* (${criterion.grade})\n`;
      text += `> _${criterion.notes}_\n\n`;
    });
  }

  // 4. Improvements (Critical Section)
  if (data.areas_for_improvement && data.areas_for_improvement.length > 0) {
    text += `🚀 *Key Improvements Needed*\n`;
    data.areas_for_improvement.forEach(point => {
      text += `• ${point}\n`;
    });
    text += `\n`;
  }

  // 5. Final Recommendation
  text += `💡 *Final Recommendation*\n`;
  text += `${data.recommendations.final_recommendation}\n`;

  // Return the result in a new field called 'formatted_text'
  return {
    json: {
      ...item.json, // Keep original data if needed
      formatted_text: text
    }
  };
});
